import{_ as t,o as r,c as a,ae as o}from"./chunks/framework.CbfcRfVi.js";const m=JSON.parse('{"title":"Getting the files","description":"","frontmatter":{},"headers":[],"relativePath":"ps4/files.md","filePath":"ps4/files.md","lastUpdated":1777892371000}'),s={name:"ps4/files.md"};function n(i,e,l,d,h,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="getting-the-files" tabindex="-1">Getting the files <a class="header-anchor" href="#getting-the-files" aria-label="Permalink to &quot;Getting the files&quot;">​</a></h1><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Some of the following links look sketchy, but the community is a divided mess for various reasons one of them being language barrier, and not many people work on the ps4. Refer to the <a href="/playstation-linux-tutorial/issues.html#other-issues">Other Issues</a> section for a rant.</p></div><h2 id="kernels" tabindex="-1">Kernels <a class="header-anchor" href="#kernels" aria-label="Permalink to &quot;Kernels&quot;">​</a></h2><p>This is the section for recommended kernels. There are both vanilla kernels and performance kernels. Ordered by newest to oldest, the top ones are the recommended ones.</p><p><a href="/playstation-linux-tutorial/ending.html#credits">Credits for all of these kernels</a>.</p><details class="details custom-block"><summary>Read this if you&#39;re confused!</summary><h3 id="do-kernel-versions-matter" tabindex="-1">Do kernel versions matter? <a class="header-anchor" href="#do-kernel-versions-matter" aria-label="Permalink to &quot;Do kernel versions matter?&quot;">​</a></h3><p>Yes, but only for Baikal, as it has been stuck on 5.4 for a while and can&#39;t use modern GPU drivers anymore. For the rest, it doesn&#39;t matter.</p><p>The community has moved on from 6.15 to 6.18, and now there is also active 7.0 kernel work for Aeolia and Belize. Baikal is still catching up.</p><h3 id="what-about-more-performance" tabindex="-1">What about more performance? <a class="header-anchor" href="#what-about-more-performance" aria-label="Permalink to &quot;What about more performance?&quot;">​</a></h3><p>If all you care about is squeezing as much performance as possible out of the PS4 (you proabbly do) try the performance kernel section. Those have patches to make the system more responsive.</p><ul><li>These kernels while still called &quot;<em>performance kernels</em>&quot; do not really improve any performance so do not expect 30% fps boost just from changing 1 file.</li></ul></details><h3 id="kernel-list" tabindex="-1">Kernel list <a class="header-anchor" href="#kernel-list" aria-label="Permalink to &quot;Kernel list&quot;">​</a></h3><p>These are normal general-use kernels with additional patches to make them work properly on the PS4.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Get the <code>bzImage_Clang_thinLTO</code>, if available. Some consoles may require the use of the <code>no-built-in-fw</code> variant.</p></div><table tabindex="0"><thead><tr><th>Kernel Download</th><th>Compatible Southbridges</th><th>Source Code</th><th>Extra info</th></tr></thead><tbody><tr><td><a href="https://github.com/rmuxnet/ps4-linux-12xx" target="_blank" rel="noreferrer">7.0-Clean</a></td><td>Aeolia, Belize</td><td><a href="https://github.com/rmuxnet/ps4-linux-12xx" target="_blank" rel="noreferrer">GitHub</a></td><td>7.0 work by rmux lives here.<br>Pick the branch or release you need from the repo.</td></tr><tr><td><a href="https://github.com/rmuxnet/ps4-linux-12xx" target="_blank" rel="noreferrer">6.18.21</a> <br> (Recommended)</td><td>Aeolia, Belize</td><td><a href="https://github.com/rmuxnet/ps4-linux-12xx" target="_blank" rel="noreferrer">GitHub</a></td><td>Prebuilts are in the repo releases even if they are not marked latest.</td></tr><tr><td><a href="https://github.com/feeRnt/ps4-linux-12xx/releases/tag/v6.15.4__crashnt-4.7" target="_blank" rel="noreferrer">6.15.4</a></td><td>Aeolia, Belize</td><td><a href="https://github.com/feeRnt/ps4-linux-12xx/" target="_blank" rel="noreferrer">GitHub</a></td><td>LTO and other improvements.<br><strong>ThinLTO</strong> recommended.</td></tr><tr><td><a href="https://github.com/feeRnt/ps4-linux-12xx/releases/tag/v5.15.15__obsidianx-4.0" target="_blank" rel="noreferrer">5.15.15</a> <br> Belize Ver.</td><td>Belize</td><td><a href="https://github.com/feeRnt/ps4-linux-12xx/" target="_blank" rel="noreferrer">GitHub</a></td><td>Same as above. Might provide better performance than 6.15.4.</td></tr><tr><td><a href="https://github.com/feeRnt/ps4-linux-12xx/releases/tag/v5.4.247__neocine-1.1" target="_blank" rel="noreferrer">5.4.247</a></td><td>Baikal</td><td><a href="https://github.com/feeRnt/ps4-linux-12xx/" target="_blank" rel="noreferrer">GitHub</a></td><td>Specific for Baikal systems. Don&#39;t use on any other console!</td></tr></tbody></table><h3 id="server-kernels" tabindex="-1">Server kernels <a class="header-anchor" href="#server-kernels" aria-label="Permalink to &quot;Server kernels&quot;">​</a></h3><p>If you are using the PS4 as a server, use these instead of the normal desktop-oriented builds when available.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Pair server kernels with the <code>128MB</code> server payload unless you have a specific reason not to.</p></div><table tabindex="0"><thead><tr><th>Kernel Download</th><th>Compatible Southbridges</th><th>Source Code</th><th>Extra info</th></tr></thead><tbody><tr><td><a href="https://github.com/rmuxnet/ps4-linux-12xx" target="_blank" rel="noreferrer">6.18.21</a> <br> (Recommended)</td><td>Aeolia, Belize</td><td><a href="https://github.com/rmuxnet/ps4-linux-12xx" target="_blank" rel="noreferrer">GitHub</a></td><td>Contains the Strawberry server prebuilts in the repo releases.</td></tr><tr><td><a href="https://github.com/rmuxnet/ps4-linux-12xx" target="_blank" rel="noreferrer">7.0-Clean</a></td><td>Aeolia, Belize</td><td><a href="https://github.com/rmuxnet/ps4-linux-12xx" target="_blank" rel="noreferrer">GitHub</a></td><td>Newer 7.0 server work by rmux.<br>Use the repo to pick the branch or release you want.</td></tr></tbody></table><details class="details custom-block"><summary>More kernels</summary><h3 id="other-kernels" tabindex="-1">Other kernels <a class="header-anchor" href="#other-kernels" aria-label="Permalink to &quot;Other kernels&quot;">​</a></h3><p>These are other kernels that you may want or need to use.</p><table tabindex="0"><thead><tr><th>Kernel Download</th><th>Compatible Southbridges</th><th>Source Code</th><th>Extra info</th></tr></thead><tbody><tr><td><a href="https://www.youtube.com/watch?v=zVzHzJT7dHk" target="_blank" rel="noreferrer">6.15,<br>5.15 and<br> 5.4</a></td><td>All</td><td>N/A</td><td>FullLTO, 120Hz support, 4K for PS4 Pro. You need to download the whole archive and pick one for your needs.<br>By saya.</td></tr><tr><td><a href="https://mega.nz/folder/N0QjHSBT#609IHevkWEW0vnTCFW-Rhw" target="_blank" rel="noreferrer">6.15.4</a></td><td>Aeolia &amp;<br>Belize</td><td>N/A?</td><td>ZRAM, CachyOS patches, KVM and more. <br>By triki1.</td></tr><tr><td><a href="https://github.com/feeRnt/ps4-linux-12xx/releases/tag/v5.15.15__1.0.0" target="_blank" rel="noreferrer">5.15.15</a> <br>Aeolia Ver.</td><td>Aeolia</td><td><a href="https://github.com/feeRnt/ps4-linux-12xx/" target="_blank" rel="noreferrer">GitHub</a></td><td>NOT RECOMMENDED.<br>Has half broken SATA/Bluray driver. Use for testing only.</td></tr></tbody></table></details><p>If you have issues, remember to check the <a href="/playstation-linux-tutorial/issues.html">Issues page</a>. If you want more help, check out <a href="/playstation-linux-tutorial/information.html#important-places">Discord servers</a>.</p><h2 id="initramfs" tabindex="-1">Initramfs <a class="header-anchor" href="#initramfs" aria-label="Permalink to &quot;Initramfs&quot;">​</a></h2><p>This is the rescue shell that boots your Linux installer/installation.</p><p>Download <a href="https://github.com/DionKill/ps4-linux-tutorial/blob/main/PS4%20Linux/initramfs.zip" target="_blank" rel="noreferrer">this one</a>. <a href="https://bitbucket.org/piotrkarbowski/better-initramfs/src/master/" target="_blank" rel="noreferrer">Source (not really)</a>.</p><details class="details custom-block"><summary>More details</summary><p>There&#39;s another in-dev initramfs (probably not working), if you want to check out the source it&#39;s <a href="https://github.com/ps4gentoo/initramfs" target="_blank" rel="noreferrer">here</a>.</p><p>Also, you may want to read <a href="https://ps4linux.com/forums/d/93-tutorial-for-building-a-custom-initramfs-research-development" target="_blank" rel="noreferrer">this post</a> on the PS4 Linux forums, it explains what an initramfs is and does in actuality.</p></details><h2 id="distros-that-you-should-use" tabindex="-1">Distros (that you should use) <a class="header-anchor" href="#distros-that-you-should-use" aria-label="Permalink to &quot;Distros (that you should use)&quot;">​</a></h2><p>There&#39;s tons of distros, tthe list of distros here are the ones that are recommended for you to use.</p><div class="danger custom-block github-alert"><p class="custom-block-title">DANGER</p><p>If you have a Baikal console (many PS4 Pros are the Baikal variant) or are otherwise using the 5.4.x kernels, make sure your distro ships with Mesa version 25.1 or lower. Newer versions are not supported on this Linux version, and so GPU acceleration will not work. See <a href="https://github.com/feeRnt/ps4-linux-12xx/issues/8" target="_blank" rel="noreferrer">this GitHub issue</a> or <a href="./baikal.html">this page to understand why</a>.</p></div><details class="details custom-block"><summary>More about these distros</summary><p>Each distro has it&#39;s own pros and cons. But most of the difference on PS4 comes down to drivers; each distro requires it&#39;s own version of them and it can be a pain in the ass to install.</p><p><strong>Arch based distros are recommended</strong>, but not because you need to be part of the elite. They are the only ones that currently have automatic updates (meaning with the rest of the system) without breaking anything.</p><p>You can of course use other distros, but you do run the risk of breaking your distro or having to reinstall everything when something needs updating, unless you know what you are doing.</p></details><table tabindex="0"><thead><tr><th>Distro</th><th>Compatible Southbridge &amp; Mesa</th><th>Port credits</th><th>Info</th></tr></thead><tbody><tr><td><a href="https://ps4linux.com/forums/d/422-cachyos-light-lxqt-a-light-and-fast-distro" target="_blank" rel="noreferrer">CachyOS Light</a></td><td>Aeolia, Belize<br>(Mesa 25.3.5)</td><td>DionKill</td><td>CachyOS, but without it running like crap. Automatic Mesa updates.<br><strong>Recommended.</strong></td></tr><tr><td><a href="https://github.com/ErkkolaMaitohappo/arch-ps4-aur-smth-fork/releases/" target="_blank" rel="noreferrer">Arch</a></td><td>Aeolia, Belize<br>(Mesa 25.3.3)</td><td><a href="https://github.com/ErkkolaMaitohappo" target="_blank" rel="noreferrer">Erkkola</a></td><td>An Arch install with different desktops: KDE, XFCE or even TempleOS!</td></tr><tr><td><a href="https://mega.nz/file/JNkUgZLY#q-XwRcz81SLyMBE_-RIpbtRZIi2pGaH-8xCc6-uFXRI" target="_blank" rel="noreferrer">Arch - Baikal Ed.</a></td><td>Baikal<br>(Mesa 25.1)</td><td><a href="https://github.com/deWaardt" target="_blank" rel="noreferrer">deeWaardt</a></td><td>Test distro. Use this if you have a Baikal system.<br><a href="https://discord.com/channels/969774306928251030/969782998029459486/1480523958817394698" target="_blank" rel="noreferrer">More info</a>.</td></tr><tr><td><a href="https://github.com/sony-jaguar-devs/distros/releases" target="_blank" rel="noreferrer">CachyOS &quot;Strawberry&quot; Server Edition</a></td><td>Aeolia, Belize</td><td><a href="https://github.com/rmuxnet/" target="_blank" rel="noreferrer">rmux</a></td><td><em>For server use only</em>! It doesn&#39;t run any DE!</td></tr><tr><td><a href="https://ps4linux.com/forums/d/265-jaguarlinux-a-ps4-linux-only-distro-beta-release/3" target="_blank" rel="noreferrer">JaguarLinux</a></td><td>Aeolia, Belize<br>(Mesa 26-devel)</td><td><a href="https://github.com/TigerClips1/" target="_blank" rel="noreferrer">TigerClips1</a></td><td>A distro made from scratch for the PS4! Void-based &amp; in development. Worth a mention.</td></tr></tbody></table><h3 id="more-distros" tabindex="-1">More distros <a class="header-anchor" href="#more-distros" aria-label="Permalink to &quot;More distros&quot;">​</a></h3><p>Here are the distros that we can&#39;t recommend anymore, as they have been superseeded, or haven&#39;t had any major updates in a while.</p><p>It may be useful to you if you want something other than Arch, or if you have a Baikal southbridge.</p><details class="details custom-block"><summary>Click here to show more distros</summary><table tabindex="0"><thead><tr><th>Distro</th><th>Compatible Southbridge &amp; Mesa</th><th>Port credits</th><th>Info</th></tr></thead><tbody><tr><td><a href="https://mega.nz/file/RyUVQARB#HZD49XXac_v2CYKD4Oqa7Tg1aiZ7ltH_cnDxixw9JjY" target="_blank" rel="noreferrer">CachyOS</a></td><td>All<br>(Mesa 25.1.0)</td><td><a href="https://www.youtube.com/channel/UCU-eXjZ7Ud0k2wC_14mqdOw" target="_blank" rel="noreferrer">Elokuba (Qba)</a></td><td>&quot;Final Fantasy v2&quot; version. It has nothing to do with FF. Mere fantasy.</td></tr><tr><td><a href="https://ps4linux.com/forums/d/386-endeavouros-gaming-rebirth" target="_blank" rel="noreferrer">EndeavourOS</a></td><td>All?<br>(Mesa Version ?)</td><td><a href="https://www.youtube.com/channel/UCU-eXjZ7Ud0k2wC_14mqdOw" target="_blank" rel="noreferrer">Elokuba (Qba)</a></td><td>Arch based distro that&#39;s nice to use and easy to maintain</td></tr><tr><td><a href="https://ps4linux.com/forums/d/342-manjaro-from-scratch" target="_blank" rel="noreferrer">Manjaro</a></td><td>All?<br>(Mesa Version ?)</td><td><a href="https://www.youtube.com/channel/UCU-eXjZ7Ud0k2wC_14mqdOw" target="_blank" rel="noreferrer">Elokuba (Qba)</a></td><td>A Manjaro KDE distro</td></tr><tr><td><a href="https://ps4linux.com/forums/d/415-garuda-dr460nized-gaming-v2/2" target="_blank" rel="noreferrer">Garuda</a></td><td>All?<br>(Mesa Version ?)</td><td><a href="https://www.youtube.com/channel/UCU-eXjZ7Ud0k2wC_14mqdOw" target="_blank" rel="noreferrer">Elokuba (Qba)</a></td><td>&quot;Gaming focused&quot; distro (not really)</td></tr><tr><td><a href="https://ps4linux.com/forums/d/399-fedora42-by-qba-triki1kdewayland" target="_blank" rel="noreferrer">Fedora 42</a></td><td>Aeolia, Belize<br>(Mesa 26)</td><td><a href="https://www.youtube.com/channel/UCU-eXjZ7Ud0k2wC_14mqdOw" target="_blank" rel="noreferrer">Elokuba (Qba)</a></td><td>Normal Fedora running KDE on Wayland</td></tr><tr><td><a href="https://ps4linux.com/forums/d/373-debian-forky-sid/3" target="_blank" rel="noreferrer">Debian Forky</a></td><td>Aeolia, Belize<br>(Mesa 25.3+)</td><td><a href="https://www.youtube.com/@trakerchris9876" target="_blank" rel="noreferrer">triki1</a></td><td>Very new distro. Extremely bleeding edge.</td></tr><tr><td><a href="https://ps4linux.com/forums/d/392-debian-forky-kali-linux-edition" target="_blank" rel="noreferrer">Kali Linux</a></td><td>All<br>(Mesa 25.0.3-devel+)</td><td><a href="https://www.youtube.com/@trakerchris9876" target="_blank" rel="noreferrer">triki1</a></td><td>Based on Debian Forky, but with Kali Linux stuff included</td></tr><tr><td><a href="https://ps4linux.com/forums/d/369-debien-trixie-full-update-mesa-2520-devel/13" target="_blank" rel="noreferrer">Debian Trixie</a></td><td>Aeolia, Belize<br>(Mesa 25.2.0-devel+)</td><td><a href="https://www.youtube.com/@trakerchris9876" target="_blank" rel="noreferrer">triki1</a></td><td>Latest Debian</td></tr><tr><td><a href="https://ps4linux.com/forums/d/337-xubuntu-2504-final-release" target="_blank" rel="noreferrer">Xubuntu</a></td><td>All<br>(Mesa 25.0.5)</td><td><a href="https://www.youtube.com/@trakerchris9876" target="_blank" rel="noreferrer">triki1</a></td><td>Divided into multiple files</td></tr><tr><td><a href="https://ps4linux.com/forums/d/252-batocera-40-for-ps4-installation-setup-tutorial" target="_blank" rel="noreferrer">Batocera 40</a></td><td>All<br>(Mesa 22.1.7)</td><td><a href="https://www.youtube.com/channel/UC9pY5BDCjDLOC4j-zkHPu8" target="_blank" rel="noreferrer">Noob404</a></td><td>For retrogaming</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Want to add more distros? Make an issue and your wish shall be granted.</p><p>Want to make your own? <a href="./distrodiy.html">Check this out!</a></p></div></details>',29)])])}const c=t(s,[["render",n]]);export{m as __pageData,c as default};
